import React, { useEffect, useState } from "react";
import { PageShell } from "@/components/orderly/PageShell";
import { Modal } from "@/components/orderly/Modal";
import { AlertTriangle, Check, ChevronRight, Trash2 } from "lucide-react";
import { OdsCheckbox } from "@/components/orderly/OdsCheckbox";
import { useTranslation } from "@/i18n";
import { useParams } from "@remix-run/react";
import {
  getLanguageOption,
  normalizeLanguageCode,
  reviewedUiLanguages,
} from "@/i18n/languages";
import {
  fetchDexCreatorDexStatus,
  deleteDexCreatorAccount,
} from "@/services/orderly";
import {
  readStoredAdminApiKey,
  signedAdminRequest,
  type StoredAdminApiKey,
} from "@/utils/adminKeyAuth";
import { toast } from "@/hooks/use-toast";
import { type Profile, getProfile } from "@/utils/branding-shared";
import { LocalizedLink } from "@/utils/localizedRoute";
import { walletGetItem, walletSetItem } from "@/utils/storage";
import { clearConnectionStorage } from "@/utils/session";

function getLoginMethod(): "wallet" | "api" | null {
  if (typeof window === "undefined") return null;
  const raw = walletGetItem("orderlyLoginContext");
  if (!raw) return null;
  try {
    const ctx = JSON.parse(raw) as { method?: "wallet" | "api" };
    return ctx.method || null;
  } catch {
    return null;
  }
}

function getFallbackDexId() {
  if (typeof window === "undefined") return null;
  return walletGetItem("orderlyDexId");
}

function getIntegrationTypeKey(value?: string) {
  if (value === "low_code" || value === "low-code")
    return "settings.integration.noCode";
  if (value === "custom" || value === "sdk")
    return "settings.integration.sdkApi";
  return "settings.notSelected";
}

function isAmbassadorProfile(profile: Profile | null) {
  return profile?.role === "ambassador" || profile?.brokerId === "ambassador";
}

function isValidDistributorName(value: string) {
  return /^[A-Za-z0-9 ._-]{4,30}$/.test(value.trim());
}

function DetailRow({
  label,
  value,
  muted,
}: {
  label: string;
  value: string;
  muted?: boolean;
}) {
  return (
    <div className="grid gap-1 px-5 py-4 sm:grid-cols-[180px_1fr] sm:gap-5">
      <p className="text-sm text-(--fg-secondary)">{label}</p>
      <p
        className={`break-all text-sm font-medium ${muted ? "text-(--fg-secondary)" : "font-mono text-(--fg-primary)"}`}
      >
        {value}
      </p>
    </div>
  );
}

function SettingsSection({
  title,
  description,
  children,
}: {
  title: string;
  description?: string;
  children: React.ReactNode;
}) {
  return (
    <section className="rounded-xl border border-(--line-subtle) bg-(--bg-surface-primary)">
      <div className="border-b border-(--line-subtle) px-5 py-4">
        <h2 className="text-base font-semibold text-(--fg-primary)">{title}</h2>
        {description && (
          <p className="mt-1 text-sm text-(--fg-secondary)">{description}</p>
        )}
      </div>
      {children}
    </section>
  );
}

export default function SettingsGeneralPage() {
  const { t, i18n } = useTranslation();
  const { lang } = useParams<{ lang: string }>();
  const locale = lang || "en";
  const [loginMethod, setLoginMethod] = useState<"wallet" | "api" | null>(null);
  const [profile, setProfile] = useState<Profile | null>(null);
  const [adminAccountId, setAdminAccountId] = useState<string | null>(null);
  const [storedAdminKey, setStoredAdminKey] =
    useState<StoredAdminApiKey | null>(null);
  const [ambassadorName, setAmbassadorName] = useState("");
  const [ambassadorNameError, setAmbassadorNameError] = useState("");
  const [ambassadorNameModalOpen, setAmbassadorNameModalOpen] = useState(false);
  const [savingAmbassadorName, setSavingAmbassadorName] = useState(false);
  const [deleteModalOpen, setDeleteModalOpen] = useState(false);
  const [deleteConfirmText, setDeleteConfirmText] = useState("");
  const [deletingAccount, setDeletingAccount] = useState(false);

  useEffect(() => {
    function refreshLocalState() {
      const storedKey = readStoredAdminApiKey();
      const nextProfile = getProfile();
      setLoginMethod(getLoginMethod());
      setProfile(nextProfile);
      setStoredAdminKey(storedKey);
      setAdminAccountId(storedKey?.accountId || nextProfile?.accountId || null);
      if (isAmbassadorProfile(nextProfile))
        setAmbassadorName(nextProfile?.builderName || "");
    }

    refreshLocalState();
    window.addEventListener("authChanged", refreshLocalState);
    window.addEventListener("storage", refreshLocalState);
    return () => {
      window.removeEventListener("authChanged", refreshLocalState);
      window.removeEventListener("storage", refreshLocalState);
    };
  }, []);

  useEffect(() => {
    if (isAmbassadorProfile(getProfile())) return;

    let cancelled = false;

    fetchDexCreatorDexStatus()
      .then(status => {
        if (cancelled || !status || status.exists === false) return;
        setProfile(current => {
          const brokerId = status.brokerId || current?.brokerId;
          return {
            ...(current || {}),
            brokerId,
            dexId: status.id || current?.dexId,
            integrationType: status.integrationType || current?.integrationType,
            pathway:
              status.integrationType === "low_code"
                ? "low-code"
                : status.integrationType === "custom"
                  ? "sdk"
                  : current?.pathway,
            graduated: Boolean(brokerId && brokerId !== "demo"),
            adminRegistered: Boolean(
              brokerId &&
                brokerId !== "demo" &&
                (status.isGraduated || current?.adminRegistered)
            ),
          };
        });
      })
      .catch(() => {
        // Settings can still render local profile data when dex-creator status is unavailable.
      });

    return () => {
      cancelled = true;
    };
  }, []);

  const isWalletLogin = loginMethod === "wallet";
  const isAmbassadorDistributor = isAmbassadorProfile(profile);
  const currentCode = normalizeLanguageCode(i18n.language) || "en";
  const currentLang = getLanguageOption(currentCode);
  const graduatedBrokerId =
    profile?.graduated && profile.brokerId && profile.brokerId !== "demo"
      ? profile.brokerId
      : null;
  const dexId = profile?.dexId || getFallbackDexId();
  const integrationType = profile?.integrationType || profile?.pathway;
  const registeredAdminAccountId = profile?.adminRegistered
    ? adminAccountId
    : null;
  const hasAdminAccess =
    isAmbassadorDistributor || profile?.adminRegistered === true;
  const hasLocalSigningKey = Boolean(
    storedAdminKey?.accountId && storedAdminKey.secret
  );
  const rememberSigningKey =
    hasLocalSigningKey && storedAdminKey?.rememberSigningKey !== false;
  const canDeleteAccount =
    !isAmbassadorDistributor && Boolean(dexId) && !profile?.graduated;

  async function updateAmbassadorName() {
    if (!isAmbassadorDistributor) return;
    const nextName = ambassadorName.trim();
    if (!isValidDistributorName(nextName)) {
      setAmbassadorNameError(t("settings.distributorNameInvalid"));
      return;
    }

    setSavingAmbassadorName(true);
    setAmbassadorNameError("");
    try {
      const response = await signedAdminRequest<{
        success?: boolean;
        message?: string;
      }>({
        endpoint: "/v1/orderly_one/vanguard/ambassador_name",
        method: "POST",
        data: { ambassador_name: nextName },
      });
      if (response?.success === false)
        throw new Error(
          response.message || t("settings.distributorNameUpdateFailed")
        );

      const nextProfile = {
        ...(profile || getProfile() || {}),
        builderName: nextName,
        brokerId: "ambassador",
        role: "ambassador",
      };
      walletSetItem("orderlyProfile", JSON.stringify(nextProfile));
      setProfile(nextProfile);
      setAmbassadorName(nextName);
      setAmbassadorNameModalOpen(false);
      window.dispatchEvent(new CustomEvent("authChanged"));
      window.dispatchEvent(new CustomEvent("profileUpdated"));
      toast({ title: t("settings.distributorNameUpdated") });
    } catch (error) {
      const message =
        error instanceof Error
          ? error.message
          : t("settings.distributorNameUpdateFailed");
      setAmbassadorNameError(message);
      toast({ title: message, variant: "destructive" });
    } finally {
      setSavingAmbassadorName(false);
    }
  }

  function updateRememberSigningKey(remember: boolean) {
    if (typeof window === "undefined") return;
    const storedKey = readStoredAdminApiKey();
    if (!storedKey?.accountId || !storedKey.secret) return;
    const nextStoredKey = { ...storedKey, rememberSigningKey: remember };
    walletSetItem("orderlyApiKey", JSON.stringify(nextStoredKey));
    setStoredAdminKey(nextStoredKey);
    setAdminAccountId(nextStoredKey.accountId || null);
    window.dispatchEvent(new CustomEvent("authChanged"));
    toast({
      title: remember
        ? t("settings.signingKeyRemembered")
        : t("settings.signingKeyForgetOnLogout"),
    });
  }

  async function handleDeleteAccount() {
    if (!dexId || !canDeleteAccount) return;
    setDeletingAccount(true);
    try {
      await deleteDexCreatorAccount(dexId);
      clearConnectionStorage();
      window.location.href = `/${locale}/login`;
    } catch (err) {
      toast({
        title: err instanceof Error ? err.message : "Failed to delete account",
        variant: "destructive",
      });
      setDeletingAccount(false);
    }
  }

  return (
    <PageShell pageTitle={t("navigation.settings")}>
      <div className="mx-auto max-w-4xl space-y-4">
        {isAmbassadorDistributor ? (
          <SettingsSection
            title={t("settings.distributorInfo")}
            description={t("settings.distributorInfoDesc")}
          >
            <div className="space-y-5 p-5">
              <div className="rounded-lg border border-(--line-subtle)">
                <div className="grid gap-3 px-5 py-4 sm:grid-cols-[180px_1fr_auto] sm:items-center sm:gap-5">
                  <p className="text-sm text-(--fg-secondary)">
                    {t("settings.distributorName")}
                  </p>
                  <p className="break-all text-sm font-medium text-(--fg-primary)">
                    {profile?.builderName || t("settings.notSet")}
                  </p>
                  <button
                    type="button"
                    onClick={() => {
                      setAmbassadorName(profile?.builderName || "");
                      setAmbassadorNameError("");
                      setAmbassadorNameModalOpen(true);
                    }}
                    className="inline-flex h-9 items-center justify-center rounded-full border border-(--line-subtle) px-4 text-sm font-medium text-(--fg-primary) transition-colors hover:bg-(--bg-hover)"
                  >
                    {t("common.update")}
                  </button>
                </div>
                <div className="border-t border-(--line-subtle)" />
                <DetailRow
                  label={t("settings.distributorAccountId")}
                  value={adminAccountId || t("settings.apiKeyNotConnected")}
                  muted={!adminAccountId}
                />
              </div>
            </div>
          </SettingsSection>
        ) : (
          <SettingsSection
            title={t("settings.workspace")}
            description={t("settings.workspaceDesc")}
          >
            <div className="divide-y divide-(--line-subtle)">
              <DetailRow
                label={t("distributor.brokerId")}
                value={graduatedBrokerId || t("settings.notGraduated")}
                muted={!graduatedBrokerId}
              />
              <DetailRow
                label={t("settings.dexId")}
                value={dexId || t("settings.notAvailable")}
                muted={!dexId}
              />
              <DetailRow
                label={t("settings.adminAccountId")}
                value={
                  registeredAdminAccountId ||
                  (profile?.adminRegistered
                    ? t("settings.registeredApiKeyNotConnected")
                    : t("settings.notRegistered"))
                }
                muted={!registeredAdminAccountId}
              />
              <DetailRow
                label={t("settings.integrationType")}
                value={t(getIntegrationTypeKey(integrationType))}
                muted={!integrationType}
              />
            </div>
          </SettingsSection>
        )}

        {hasAdminAccess && (
          <SettingsSection
            title={t("settings.security")}
            description={t("settings.securityDesc")}
          >
            <div className="space-y-3 p-5">
              <label
                className={`flex items-start gap-3 rounded-lg border border-(--line-subtle) px-4 py-3 text-sm ${hasLocalSigningKey ? "cursor-pointer transition-colors hover:bg-(--bg-hover)" : "opacity-60"}`}
              >
                <OdsCheckbox
                  checked={rememberSigningKey}
                  disabled={!hasLocalSigningKey}
                  onCheckedChange={checked =>
                    updateRememberSigningKey(checked === true)
                  }
                  className="mt-0.5"
                />
                <span>
                  <span className="block font-medium text-(--fg-primary)">
                    {t("settings.rememberSigningKey")}
                  </span>
                  <span className="mt-0.5 block text-xs text-(--fg-secondary)">
                    {hasLocalSigningKey
                      ? t("settings.rememberSigningKeyDesc")
                      : t("settings.noSigningKey")}
                  </span>
                </span>
              </label>

              {!isWalletLogin && (
                <div className="flex items-start gap-3 rounded-lg border border-[rgba(255,99,144,0.25)] bg-[rgba(255,99,144,0.08)] px-3 py-2.5 text-sm text-[#FF6390]">
                  <AlertTriangle className="mt-0.5 h-4 w-4 shrink-0" />
                  <span>
                    <span className="font-medium">
                      {t("settings.walletLoginRequired")}
                    </span>{" "}
                    {t("settings.walletLoginRequiredDesc")}
                  </span>
                </div>
              )}

              {isWalletLogin ? (
                <LocalizedLink
                  to="/settings/api-keys"
                  className="flex items-center justify-between rounded-lg border border-(--line-subtle) px-4 py-3 text-sm transition-colors hover:bg-(--bg-hover)"
                >
                  <span>
                    <span className="block font-medium text-(--fg-primary)">
                      {t("settings.orderlyApiKeys")}
                    </span>
                    <span className="mt-0.5 block text-xs text-(--fg-secondary)">
                      {t("settings.orderlyApiKeysDesc")}
                    </span>
                  </span>
                  <ChevronRight className="h-4 w-4 text-(--fg-secondary)" />
                </LocalizedLink>
              ) : (
                <div className="flex items-center justify-between rounded-lg border border-(--line-subtle) px-4 py-3 text-sm opacity-60">
                  <span>
                    <span className="block font-medium text-(--fg-primary)">
                      {t("settings.orderlyApiKeys")}
                    </span>
                    <span className="mt-0.5 block text-xs text-(--fg-secondary)">
                      {t("settings.connectWalletToManageKeys")}
                    </span>
                  </span>
                  <ChevronRight className="h-4 w-4 text-(--fg-secondary)" />
                </div>
              )}
            </div>
          </SettingsSection>
        )}

        <SettingsSection
          title={t("language.selectLanguage")}
          description={`${t("common.current")}: ${currentLang.label}`}
        >
          <div className="grid grid-cols-1 gap-2 p-5 sm:grid-cols-2 lg:grid-cols-5">
            {reviewedUiLanguages.map(uiLang => {
              const isActive = currentCode === uiLang.code;
              return (
                <button
                  key={uiLang.code}
                  type="button"
                  onClick={() => i18n.changeLanguage(uiLang.code)}
                  className={`flex items-center justify-between rounded-lg border px-3 py-2.5 text-sm transition-colors ${
                    isActive
                      ? "border-(--line-brand) bg-[rgba(188,135,255,0.10)] text-(--fg-brand)"
                      : "border-(--line-subtle) text-(--fg-primary) hover:bg-(--bg-hover)"
                  }`}
                >
                  <span className="font-medium">{uiLang.label}</span>
                  {isActive && <Check className="h-4 w-4 text-(--fg-brand)" />}
                </button>
              );
            })}
          </div>
        </SettingsSection>

        {canDeleteAccount && (
          <section className="rounded-xl border border-[rgba(255,99,144,0.25)] bg-[rgba(255,99,144,0.04)]">
            <div className="border-b border-[rgba(255,99,144,0.25)] px-5 py-4">
              <h2 className="text-base font-semibold text-[#FF6390]">
                {t("settings.dangerZone")}
              </h2>
              <p className="mt-1 text-sm text-(--fg-secondary)">
                {t("settings.dangerZoneDesc")}
              </p>
            </div>
            <div className="flex items-center justify-between gap-4 px-5 py-4">
              <p className="text-sm text-(--fg-secondary)">
                {t("settings.deleteAccountWarning")}
              </p>
              <button
                type="button"
                onClick={() => {
                  setDeleteConfirmText("");
                  setDeleteModalOpen(true);
                }}
                className="inline-flex h-10 shrink-0 items-center justify-center gap-2 rounded-full border border-[rgba(255,99,144,0.35)] bg-transparent px-5 text-sm font-medium text-[#FF6390] transition-colors hover:bg-[rgba(255,99,144,0.10)]"
              >
                <Trash2 className="h-4 w-4" />
                {t("settings.deleteAccount")}
              </button>
            </div>
          </section>
        )}
      </div>

      <Modal
        open={ambassadorNameModalOpen}
        onClose={() => {
          if (!savingAmbassadorName) setAmbassadorNameModalOpen(false);
        }}
        title={t("settings.updateDistributorName")}
      >
        <div className="space-y-5">
          <label className="block">
            <span className="mb-2 block text-sm font-medium text-(--fg-primary)">
              {t("settings.distributorName")}
            </span>
            <input
              type="text"
              value={ambassadorName}
              onChange={event => {
                setAmbassadorName(event.target.value);
                setAmbassadorNameError("");
              }}
              maxLength={30}
              className="h-11 w-full rounded-lg border border-(--line-subtle) bg-(--bg-surface-secondary) px-3 text-sm text-(--fg-primary) outline-none transition-colors focus:border-(--line-brand)"
              placeholder={t("settings.enterDistributorName")}
            />
            <span
              className={`mt-2 block text-xs ${ambassadorNameError ? "text-(--fg-negative)" : "text-(--fg-secondary)"}`}
            >
              {ambassadorNameError || t("settings.distributorNameHelp")}
            </span>
          </label>
          <div className="flex justify-end gap-3">
            <button
              type="button"
              disabled={savingAmbassadorName}
              onClick={() => setAmbassadorNameModalOpen(false)}
              className="inline-flex h-10 items-center justify-center rounded-full border border-(--line-subtle) px-4 text-sm font-medium text-(--fg-primary) transition-colors hover:bg-(--bg-hover) disabled:cursor-not-allowed disabled:opacity-50"
            >
              {t("common.cancel")}
            </button>
            <button
              type="button"
              disabled={
                savingAmbassadorName ||
                ambassadorName.trim() === (profile?.builderName || "").trim()
              }
              onClick={() => void updateAmbassadorName()}
              className="inline-flex h-10 items-center justify-center rounded-full px-5 text-sm font-semibold text-white transition-opacity hover:opacity-90 disabled:cursor-not-allowed disabled:opacity-50"
              style={{ background: "var(--bg-brand-grad)" }}
            >
              {savingAmbassadorName ? t("common.saving") : t("common.save")}
            </button>
          </div>
        </div>
      </Modal>

      <Modal
        open={canDeleteAccount && deleteModalOpen}
        onClose={() => {
          if (!deletingAccount) setDeleteModalOpen(false);
        }}
        title={t("settings.deleteAccount")}
      >
        <div className="space-y-5">
          <div className="flex items-start gap-3 rounded-lg border border-[rgba(255,99,144,0.25)] bg-[rgba(255,99,144,0.08)] px-3 py-2.5 text-sm text-[#FF6390]">
            <AlertTriangle className="mt-0.5 h-4 w-4 shrink-0" />
            <span>{t("settings.deleteAccountWarning")}</span>
          </div>
          <label className="block">
            <span className="mb-2 block text-sm font-medium text-(--fg-primary)">
              {t("settings.deleteAccountConfirm")}
            </span>
            <input
              type="text"
              value={deleteConfirmText}
              onChange={e => setDeleteConfirmText(e.target.value)}
              className="h-11 w-full rounded-lg border border-(--line-subtle) bg-(--bg-surface-secondary) px-3 text-sm text-(--fg-primary) outline-none transition-colors focus:border-(--line-brand)"
              placeholder="DELETE"
              autoComplete="off"
            />
          </label>
          <div className="flex justify-end gap-3">
            <button
              type="button"
              disabled={deletingAccount}
              onClick={() => setDeleteModalOpen(false)}
              className="inline-flex h-10 items-center justify-center rounded-full border border-(--line-subtle) px-4 text-sm font-medium text-(--fg-primary) transition-colors hover:bg-(--bg-hover) disabled:cursor-not-allowed disabled:opacity-50"
            >
              {t("common.cancel")}
            </button>
            <button
              type="button"
              disabled={deletingAccount || deleteConfirmText !== "DELETE"}
              onClick={() => void handleDeleteAccount()}
              className="inline-flex h-10 items-center justify-center rounded-full bg-[#FF6390] px-5 text-sm font-semibold text-white transition-opacity hover:opacity-90 disabled:cursor-not-allowed disabled:opacity-50"
            >
              {deletingAccount
                ? t("common.saving")
                : t("settings.deleteAccount")}
            </button>
          </div>
        </div>
      </Modal>
    </PageShell>
  );
}
